document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("sendApologistikoButton");e&&e.addEventListener("click",async()=>{try{const t=document.getElementById("ypokatasthmata")?.value||"",a=document.getElementById("ypokatasthmata_stathera")?.value||"",o=document.getElementById("apo_hmeromhnia")?.value||"",n=document.getElementById("eos_hmeromhnia")?.value||"",s=document.getElementById("_csrf")?.value||"";if(!a||!o||!n)return Swal.fire({icon:"warning",title:"Ελλιπή στοιχεία",text:"Συμπληρώστε παράρτημα και ημερομηνίες.",width:"42rem",customClass:{popup:"swal-wide-text"}});e.disabled=!0;const i=await fetch("/ergazomenoi/programmata/wtoApologistiko",{method:"POST",headers:{"Content-Type":"application/json","CSRF-Token":s},body:JSON.stringify({ypokatasthmata:t,ypokatasthmata_stathera:a,apo_hmeromhnia:o,eos_hmeromhnia:n})}),r=await i.json();if(console.log("✅ WTO APOLOGISTIKO RESULT:",r),!i.ok||!r.success)throw new Error(r.message||"Αποτυχία δημιουργίας XML.");Swal.fire({icon:"success",title:"Επιτυχία",html:`\n                    <div style="text-align:left;">\n                        <div>${r.message||"Το XML δημιουργήθηκε επιτυχώς."}</div>\n\n                        <hr>\n\n                        <div style="font-size:0.85rem; word-break:break-word;">\n                            <b>XML:</b><br>\n                            ${r.filename||"-"}\n                        </div>\n\n                        <div style="margin-top:8px; font-size:0.8rem; color:#666; word-break:break-word;">\n                            ${r.s3Key||""}\n                        </div>\n                    </div>\n                `,width:"42rem",customClass:{popup:"swal-wide-text"}})}catch(e){console.error("❌ WTO APOLOGISTIKO FRONT ERROR:",e),Swal.fire({icon:"error",title:"Σφάλμα",text:e.message||"Αποτυχία δημιουργίας XML.",width:"42rem",customClass:{popup:"swal-wide-text"}})}finally{e.disabled=!1}})});